'use strict';(function(){const indexCfg={};indexCfg.doc={id:'id',field:['title','content'],store:['title','href','parent'],};const index=FlexSearch.create(indexCfg);window.geekdocSearchIndex=index;index.add({'id':0,'href':'/','title':"Home",'parent':'','content':"Welcome to alexsalter.net\u0026hellip; are you lost?\n"});index.add({'id':1,'href':'/note/debian/go/','title':"Go",'parent':"Debian",'content':"version=\u0026#34;1.15.6\u0026#34; wget https://golang.org/dl/go${version}.linux-amd64.tar.gz -O go.tar.gz tar -xvf go.tar.gz sudo mv go /usr/local rm go.tar.gz mkdir -p ~/go/bin Add environment variables\nexport GOROOT=/usr/local/go export GOPATH=~/go export PATH=$GOPATH/bin:$GOROOT/bin:$PATH "});index.add({'id':2,'href':'/note/','title':"Notes",'parent':"Home",'content':""});index.add({'id':3,'href':'/note/debian/zsh/','title':"zsh",'parent':"Debian",'content':"My theme Download https://github.com/saltera/my-zsh-theme/blob/master/my.zsh-theme to $ZSH/custom/themes/my.zsh-theme\n# vim:ft=zsh ts=2 sw=2 sts=2 # # My theme is a slightly customized agnoster - https://gist.github.com/3712874 # A Powerline-inspired theme for ZSH # # # README # # In order for this theme to render correctly, you will need a # [Powerline-patched font](https://github.com/Lokaltog/powerline-fonts). # Make sure you have a recent version: the code points that Powerline # uses changed in 2012, and older versions will display incorrectly, # in confusing ways. # # In addition, I recommend the # [Solarized theme](https://github.com/altercation/solarized/) and, if you\u0026#39;re # using it on Mac OS X, [iTerm 2](https://iterm2.com/) over Terminal.app - # it has significantly better color fidelity. # # If using with \u0026#34;light\u0026#34; variant of the Solarized color schema, set # SOLARIZED_THEME variable to \u0026#34;light\u0026#34;. If you don\u0026#39;t specify, we\u0026#39;ll assume # you\u0026#39;re using the \u0026#34;dark\u0026#34; variant. # # # Goals # # The aim of this theme is to only show you *relevant* information. Like most # prompts, it will only show git information when in a git working directory. # However, it goes a step further: everything from the current user and # hostname to whether the last call exited with an error to whether background # jobs are running in this shell will all be displayed automatically when # appropriate. ### Segment drawing # A few utility functions to make it easy and re-usable to draw segmented prompts CURRENT_BG=\u0026#39;NONE\u0026#39; case ${SOLARIZED_THEME:-dark} in light) CURRENT_FG=\u0026#39;white\u0026#39;;; *) CURRENT_FG=\u0026#39;black\u0026#39;;; esac # Special Powerline characters () { local LC_ALL=\u0026#34;\u0026#34; LC_CTYPE=\u0026#34;en_US.UTF-8\u0026#34; # NOTE: This segment separator character is correct. In 2012, Powerline changed # the code points they use for their special characters. This is the new code point. # If this is not working for you, you probably have an old version of the # Powerline-patched fonts installed. Download and install the new version. # Do not submit PRs to change this unless you have reviewed the Powerline code point # history and have new information. # This is defined using a Unicode escape sequence so it is unambiguously readable, regardless of # what font the user is viewing this source code in. Do not replace the # escape sequence with a single literal character. # Do not change this! Do not make it \u0026#39;\\u2b80\u0026#39;; that is the old, wrong code point. SEGMENT_SEPARATOR=$\u0026#39;\\ue0b0\u0026#39; } # Begin a segment # Takes two arguments, background and foreground. Both can be omitted, # rendering default background/foreground. prompt_segment() { local bg fg [[ -n $1 ]] \u0026amp;\u0026amp; bg=\u0026#34;%K{$1}\u0026#34; || bg=\u0026#34;%k\u0026#34; [[ -n $2 ]] \u0026amp;\u0026amp; fg=\u0026#34;%F{$2}\u0026#34; || fg=\u0026#34;%f\u0026#34; if [[ $CURRENT_BG != \u0026#39;NONE\u0026#39; \u0026amp;\u0026amp; $1 != $CURRENT_BG ]]; then echo -n \u0026#34; %{$bg%F{$CURRENT_BG}%}$SEGMENT_SEPARATOR%{$fg%} \u0026#34; else echo -n \u0026#34;%{$bg%}%{$fg%} \u0026#34; fi CURRENT_BG=$1 [[ -n $3 ]] \u0026amp;\u0026amp; echo -n $3 } # End the prompt, closing any open segments prompt_end() { if [[ -n $CURRENT_BG ]]; then echo -n \u0026#34; %{%k%F{$CURRENT_BG}%}$SEGMENT_SEPARATOR\u0026#34; else echo -n \u0026#34;%{%k%}\u0026#34; fi echo -n \u0026#34;%{%f%}\u0026#34; CURRENT_BG=\u0026#39;\u0026#39; printf \u0026#34;\\nᐅ \u0026#34;; } ### Prompt components # Each component will draw itself, and hide itself if no information needs to be shown # Context: user@hostname (who am I and where am I) prompt_context() { if [[ \u0026#34;$USER\u0026#34; != \u0026#34;$DEFAULT_USER\u0026#34; || -n \u0026#34;$SSH_CLIENT\u0026#34; ]]; then prompt_segment black default \u0026#34;%(!.%{%F{yellow}%}.)%n@%m\u0026#34; fi } # Git: branch/detached head, dirty status prompt_git() { (( $+commands[git] )) || return if [[ \u0026#34;$(git config --get oh-my-zsh.hide-status 2\u0026gt;/dev/null)\u0026#34; = 1 ]]; then return fi local PL_BRANCH_CHAR () { local LC_ALL=\u0026#34;\u0026#34; LC_CTYPE=\u0026#34;en_US.UTF-8\u0026#34; PL_BRANCH_CHAR=$\u0026#39;\\ue0a0\u0026#39; #  } local ref dirty mode repo_path if [[ \u0026#34;$(git rev-parse --is-inside-work-tree 2\u0026gt;/dev/null)\u0026#34; = \u0026#34;true\u0026#34; ]]; then repo_path=$(git rev-parse --git-dir 2\u0026gt;/dev/null) dirty=$(parse_git_dirty) ref=$(git symbolic-ref HEAD 2\u0026gt; /dev/null) || ref=\u0026#34;➦ $(git rev-parse --short HEAD 2\u0026gt; /dev/null)\u0026#34; if [[ -n $dirty ]]; then prompt_segment yellow black else prompt_segment green $CURRENT_FG fi if [[ -e \u0026#34;${repo_path}/BISECT_LOG\u0026#34; ]]; then mode=\u0026#34; \u0026lt;B\u0026gt;\u0026#34; elif [[ -e \u0026#34;${repo_path}/MERGE_HEAD\u0026#34; ]]; then mode=\u0026#34; \u0026gt;M\u0026lt;\u0026#34; elif [[ -e \u0026#34;${repo_path}/rebase\u0026#34; || -e \u0026#34;${repo_path}/rebase-apply\u0026#34; || -e \u0026#34;${repo_path}/rebase-merge\u0026#34; || -e \u0026#34;${repo_path}/../.dotest\u0026#34; ]]; then mode=\u0026#34; \u0026gt;R\u0026gt;\u0026#34; fi setopt promptsubst autoload -Uz vcs_info zstyle \u0026#39;:vcs_info:*\u0026#39; enable git zstyle \u0026#39;:vcs_info:*\u0026#39; get-revision true zstyle \u0026#39;:vcs_info:*\u0026#39; check-for-changes true zstyle \u0026#39;:vcs_info:*\u0026#39; stagedstr \u0026#39;✚\u0026#39; zstyle \u0026#39;:vcs_info:*\u0026#39; unstagedstr \u0026#39;±\u0026#39; zstyle \u0026#39;:vcs_info:*\u0026#39; formats \u0026#39; %u%c\u0026#39; zstyle \u0026#39;:vcs_info:*\u0026#39; actionformats \u0026#39; %u%c\u0026#39; vcs_info echo -n \u0026#34;${ref/refs\\/heads\\//$PL_BRANCH_CHAR}${vcs_info_msg_0_%% }${mode}\u0026#34; fi } prompt_bzr() { (( $+commands[bzr] )) || return # Test if bzr repository in directory hierarchy local dir=\u0026#34;$PWD\u0026#34; while [[ ! -d \u0026#34;$dir/.bzr\u0026#34; ]]; do [[ \u0026#34;$dir\u0026#34; = \u0026#34;/\u0026#34; ]] \u0026amp;\u0026amp; return dir=\u0026#34;${dir:h}\u0026#34; done local bzr_status status_mod status_all revision if bzr_status=$(bzr status 2\u0026gt;\u0026amp;1); then status_mod=$(echo -n \u0026#34;$bzr_status\u0026#34; | head -n1 | grep \u0026#34;modified\u0026#34; | wc -m) status_all=$(echo -n \u0026#34;$bzr_status\u0026#34; | head -n1 | wc -m) revision=$(bzr log -r-1 --log-format line | cut -d: -f1) if [[ $status_mod -gt 0 ]] ; then prompt_segment yellow black \u0026#34;bzr@$revision✚\u0026#34; else if [[ $status_all -gt 0 ]] ; then prompt_segment yellow black \u0026#34;bzr@$revision\u0026#34; else prompt_segment green black \u0026#34;bzr@$revision\u0026#34; fi fi fi } prompt_hg() { (( $+commands[hg] )) || return local rev st branch if $(hg id \u0026gt;/dev/null 2\u0026gt;\u0026amp;1); then if $(hg prompt \u0026gt;/dev/null 2\u0026gt;\u0026amp;1); then if [[ $(hg prompt \u0026#34;{status|unknown}\u0026#34;) = \u0026#34;?\u0026#34; ]]; then # if files are not added prompt_segment red white st=\u0026#39;±\u0026#39; elif [[ -n $(hg prompt \u0026#34;{status|modified}\u0026#34;) ]]; then # if any modification prompt_segment yellow black st=\u0026#39;±\u0026#39; else # if working copy is clean prompt_segment green $CURRENT_FG fi echo -n $(hg prompt \u0026#34;☿ {rev}@{branch}\u0026#34;) $st else st=\u0026#34;\u0026#34; rev=$(hg id -n 2\u0026gt;/dev/null | sed \u0026#39;s/[^-0-9]//g\u0026#39;) branch=$(hg id -b 2\u0026gt;/dev/null) if `hg st | grep -q \u0026#34;^\\?\u0026#34;`; then prompt_segment red black st=\u0026#39;±\u0026#39; elif `hg st | grep -q \u0026#34;^[MA]\u0026#34;`; then prompt_segment yellow black st=\u0026#39;±\u0026#39; else prompt_segment green $CURRENT_FG fi echo -n \u0026#34;☿ $rev@$branch\u0026#34; $st fi fi } # Dir: current working directory prompt_dir() { prompt_segment blue $CURRENT_FG \u0026#39;%~\u0026#39; } # Virtualenv: current working virtualenv prompt_virtualenv() { local virtualenv_path=\u0026#34;$VIRTUAL_ENV\u0026#34; if [[ -n $virtualenv_path \u0026amp;\u0026amp; -n $VIRTUAL_ENV_DISABLE_PROMPT ]]; then prompt_segment blue black \u0026#34;(`basename $virtualenv_path`)\u0026#34; fi } # Status: # - was there an error # - am I root # - are there background jobs? prompt_status() { local -a symbols [[ $RETVAL -ne 0 ]] \u0026amp;\u0026amp; symbols+=\u0026#34;%{%F{red}%}✘\u0026#34; [[ $UID -eq 0 ]] \u0026amp;\u0026amp; symbols+=\u0026#34;%{%F{yellow}%}⚡\u0026#34; [[ $(jobs -l | wc -l) -gt 0 ]] \u0026amp;\u0026amp; symbols+=\u0026#34;%{%F{cyan}%}⚙\u0026#34; [[ -n \u0026#34;$symbols\u0026#34; ]] \u0026amp;\u0026amp; prompt_segment black default \u0026#34;$symbols\u0026#34; } #AWS Profile: # - display current AWS_PROFILE name # - displays yellow on red if profile name contains \u0026#39;production\u0026#39; or # ends in \u0026#39;-prod\u0026#39; # - displays black on green otherwise prompt_aws() { [[ -z \u0026#34;$AWS_PROFILE\u0026#34; || \u0026#34;$SHOW_AWS_PROMPT\u0026#34; = false ]] \u0026amp;\u0026amp; return case \u0026#34;$AWS_PROFILE\u0026#34; in *-prod|*production*) prompt_segment red yellow \u0026#34;AWS: $AWS_PROFILE\u0026#34; ;; *) prompt_segment green black \u0026#34;AWS: $AWS_PROFILE\u0026#34; ;; esac } prompt_kube() { context=$(kubectl config current-context 2\u0026gt; /dev/null | sed -e \u0026#39;s/aks-\\(.*\\)-admin/\\1/\u0026#39;) if [ -z \u0026#34;$context\u0026#34; ]; then; return; fi namespace=$(kubectl config view --minify --output \u0026#39;jsonpath={..namespace}\u0026#39;) case \u0026#34;$context\u0026#34; in ajs*) prompt_segment 006 white \u0026#34;⎈ ${context}/${namespace}\u0026#34;;; ci*) prompt_segment green white \u0026#34;⎈ ${context}/${namespace}\u0026#34;;; stage*) prompt_segment 130 white \u0026#34;⎈ ${context}/${namespace}\u0026#34;;; prod*) prompt_segment red white \u0026#34;⎈ ${context}/${namespace}\u0026#34;;; *) prompt_segment black white \u0026#34;⎈ ${context}/${namespace}\u0026#34;;; esac } ## Main prompt build_prompt() { RETVAL=$? prompt_status prompt_virtualenv prompt_aws prompt_context prompt_dir prompt_git prompt_bzr prompt_hg prompt_kube prompt_end } source $ZSH/plugins/kube-ps1/kube-ps1.plugin.zsh PROMPT=\u0026#39;%{%f%b%k%}$(build_prompt)\u0026#39; ~/.zshrc\nexport ZSH=\u0026#34;~/.oh-my-zsh\u0026#34; ZSH_THEME=\u0026#34;my\u0026#34; plugins=(git golang kubectl kube-ps1) source $ZSH/oh-my-zsh.sh export GOROOT=/usr/local/go export GOPATH=~/go export PATH=$GOPATH/bin:$GOROOT/bin:$PATH alias kcu=\u0026#34;kubectl config unset current-context\u0026#34; "});index.add({'id':4,'href':'/note/debian/packages-third-party/','title':"Packages (third party)",'parent':"Debian",'content':"Azure CLI curl -sL https://packages.microsoft.com/keys/microsoft.asc \\  | gpg --dearmor \\  | tee /etc/apt/trusted.gpg.d/microsoft.gpg \u0026gt; /dev/null AZ_REPO=$(lsb_release -cs) echo \u0026#34;deb [arch=amd64] https://packages.microsoft.com/repos/azure-cli/ $AZ_REPOmain\u0026#34; \\  | tee /etc/apt/sources.list.d/azure-cli.list apt update apt install azure-cli Docker curl -fsSL https://download.docker.com/linux/debian/gpg \\  | apt-key add - add-apt-repository \u0026#34;deb [arch=amd64] https://download.docker.com/linux/debian $(lsb_release -cs)stable\u0026#34; apt update apt install docker-ce usermod -aG docker ${USER} su - ${USER} Disable zfs plugin in /etc/containerd/config.toml\ndisabled_plugins = [\u0026quot;cri\u0026quot;, \u0026quot;zfs\u0026quot;] GitHub CLI apt-key adv --keyserver keyserver.ubuntu.com --recv-key C99B11DEB97541F0 apt-add-repository https://cli.github.com/packages apt update apt install gh Helm curl https://baltocdn.com/helm/signing.asc \\ | apt-key add - echo \u0026quot;deb https://baltocdn.com/helm/stable/debian/ all main\u0026quot; \\ | tee /etc/apt/sources.list.d/helm-stable-debian.list apt-get update apt-get install helm Kubectl curl -s https://packages.cloud.google.com/apt/doc/apt-key.gpg \\  | apt-key add - echo \u0026#34;deb https://apt.kubernetes.io/ kubernetes-xenial main\u0026#34; \\  | tee -a /etc/apt/sources.list.d/kubernetes.list apt-get update apt-get install kubectl Microsoft .NET SDK wget https://packages.microsoft.com/config/debian/10/packages-microsoft-prod.deb \\  -O packages-microsoft-prod.deb dpkg -i packages-microsoft-prod.deb rm packages-microsoft-prod.deb apt-get update apt-get install -y dotnet-sdk-3.1 apt-get install -y dotnet-sdk-5.0 Terraform curl -fsSL https://apt.releases.hashicorp.com/gpg \\  | sudo apt-key add - sudo apt-add-repository \u0026#34;deb [arch=$(dpkg --print-architecture)] https://apt.releases.hashicorp.com $(lsb_release -cs)main\u0026#34; apt update apt install terraform Visual Code curl -sSL https://packages.microsoft.com/keys/microsoft.asc \\  | apt-key add - add-apt-repository \u0026#34;deb [arch=amd64] https://packages.microsoft.com/repos/vscode stable main\u0026#34; apt update apt install code "});index.add({'id':5,'href':'/note/debian/gnome-extensions/','title':"Gnome extensions",'parent':"Debian",'content':"Install the gnome-shell-extensions package.\napt update apt install gnome-shell-extensions Activate packages on https://extensions.gnome.org\n No top left hot corner Sound output device chooser Todo txt  "});index.add({'id':6,'href':'/note/debian/appearance/','title':"Appearance",'parent':"Debian",'content':"Change the theme to Adwaita-dark\ngsettings set org.gnome.desktop.interface gtk-theme \u0026#34;Adwaita-dark\u0026#34; "});index.add({'id':7,'href':'/note/debian/audioengine-hd3/','title':"Audioengine HD3",'parent':"Debian",'content':"The Audioengine HD3 speakers do not appear to support a sample rate of 44.1kHz which is the default.\nWe therefore need change the sample rate to 48kHz and restart pulseaudio.\nsed \\  -i \u0026#39;s/; default-sample-rate = 44100/default-sample-rate = 48000/g\u0026#39; \\  /etc/pulse/daemon.conf pulseaudio -k "});index.add({'id':8,'href':'/note/debian/packages/','title':"Packages",'parent':"Debian",'content':"Main    Name Description     bridge-utils Utilities for configuring the Linux Ethernet bridge   dnsutils Clients provided with BIND   gimp    git    htop interactive processes viewer   inkscape    hwinfo Hardware identification system   openssh-server    pavucontrol    tree displays an indented directory tree, in color    apt update apt install \\  apt-transport-https \\  bridge-utils \\  ca-certificates \\  curl \\  dnsutils \\  gimp \\  git \\  gnupg \\  gnupg2 \\  htop \\  hwinfo \\  inkscape \\  lsb-release \\  openssh-server \\  pavucontrol \\  software-properties-common \\  tree Restricted apt install \\  gstreamer1.0-libav \\  gstreamer1.0-plugins-ugly \\  gstreamer1.0-vaapi \\  intel-microcode \\  libavcodec-extra \\  rar \\  ttf-mscorefonts-installer \\  unrar "});index.add({'id':9,'href':'/note/debian/','title':"Debian",'parent':"Notes",'content':""});index.add({'id':10,'href':'/note/debian/dell-xps-15-9560/','title':"Dell XPS 15 9560",'parent':"Debian",'content':"Installer missing non-free wifi firmware The Intel 8265/8275 requires non-free firmware whoever this can be added to the installation media.\nCopy the non-free firmware-iwlwifi_*_all.deb from https://cdimage.debian.org/cdimage/unofficial/non-free/firmware/ to firmware folder of the installation media.\nACPI issue There is currently a bug that means that some kernels (particularly newer ones) will detect the wrong ACPI revision.\nAdd acpi_rev_override=5 to /etc/default/grub\nGRUB_CMDLINE_LINUX=\u0026#34;acpi_rev_override=5 quiet\u0026#34; Update grub\nupdate-grub Reference    Name Link     Debian XPS 15 9560 https://wiki.debian.org/InstallingDebianOn/Dell/Dell_XPS_15_9560   Non-free firmware https://cdimage.debian.org/cdimage/unofficial/non-free/firmware/    "});index.add({'id':11,'href':'/categories/','title':"Categories",'parent':"Home",'content':""});index.add({'id':12,'href':'/tags/','title':"Tags",'parent':"Home",'content':""});})();